        private static List<FilterParameter> ParseFilters(HttpRequest req, HashSet<string> allowedColumns)
        {
            var filters = new List<FilterParameter>();

            // Parse query string parameters in format: filter_ColumnName_operator=value
            // Example: filter_Region_eq=West&filter_Amount_gte=100&filter_Status_in=Active,Pending
            foreach (var key in req.Query.Keys)
            {
                if (!key.StartsWith("filter_", StringComparison.OrdinalIgnoreCase))
                    continue;

                var parts = key.Split('_', 3);
                if (parts.Length != 3)
                    continue;

                var columnName = parts[1];
                var operatorKey = parts[2];

                // Validate column name against whitelist
                if (!allowedColumns.Contains(columnName))
                {
                    throw new ArgumentException(
                        $"Invalid filter column: '{columnName}'. Allowed columns: {string.Join(", ", allowedColumns)}");
                }

                // Validate operator against whitelist
                if (!AllowedOperators.TryGetValue(operatorKey, out var sqlOperator))
                {
                    throw new ArgumentException(
                        $"Invalid operator: '{operatorKey}'. Allowed operators: {string.Join(", ", AllowedOperators.Keys)}");
                }

                var value = req.Query[key].ToString();
                if (string.IsNullOrEmpty(value))
                    continue;

                // Get the actual column name from the whitelist (preserves casing)
                var actualColumnName = allowedColumns.First(c =>
                    c.Equals(columnName, StringComparison.OrdinalIgnoreCase));

                filters.Add(new FilterParameter
                {
                    ColumnName = actualColumnName,
                    Operator = sqlOperator,
                    OperatorKey = operatorKey.ToLower(),
                    Value = value
                });
            }

            return filters;
        }

        private static List<string> ParseSelectColumns(HttpRequest req, HashSet<string> allowedColumns)
        {
            var selectParam = req.Query["select"].ToString();
            if (string.IsNullOrEmpty(selectParam))
                return null; // null means SELECT *

            var requestedColumns = selectParam.Split(',', StringSplitOptions.RemoveEmptyEntries);
            var validColumns = new List<string>();

            foreach (var col in requestedColumns)
            {
                var trimmed = col.Trim();
                if (!allowedColumns.Contains(trimmed))
                {
                    throw new ArgumentException(
                        $"Invalid select column: '{trimmed}'. Allowed columns: {string.Join(", ", allowedColumns)}");
                }

                var actualColumnName = allowedColumns.First(c =>
                    c.Equals(trimmed, StringComparison.OrdinalIgnoreCase));
                validColumns.Add(actualColumnName);
            }

            return validColumns.Any() ? validColumns : null;
        }

        private static (string Column, string Direction) ParseSorting(HttpRequest req, HashSet<string> allowedColumns)
        {
            var sortColumn = req.Query["sortBy"].ToString();
            var sortDirection = req.Query["sortDir"].ToString();

            if (string.IsNullOrEmpty(sortColumn))
                return (null, null);

            if (!allowedColumns.Contains(sortColumn))
            {
                throw new ArgumentException(
                    $"Invalid sort column: '{sortColumn}'. Allowed columns: {string.Join(", ", allowedColumns)}");
            }

            var actualColumnName = allowedColumns.First(c =>
                c.Equals(sortColumn, StringComparison.OrdinalIgnoreCase));

            if (string.IsNullOrEmpty(sortDirection) || !AllowedSortDirections.Contains(sortDirection))
            {
                sortDirection = "ASC";
            }

            return (actualColumnName, sortDirection.ToUpper());
        }

        private static (int PageNumber, int PageSize) ParsePaging(HttpRequest req)
        {
            int pageNumber = 1;
            int pageSize = 50;
            const int maxPageSize = 1000;

            if (int.TryParse(req.Query["page"], out var parsedPage) && parsedPage > 0)
                pageNumber = parsedPage;

            if (int.TryParse(req.Query["pageSize"], out var parsedSize) && parsedSize > 0)
                pageSize = Math.Min(parsedSize, maxPageSize);

            return (pageNumber, pageSize);
        }

        private static QueryResult BuildParameterizedQuery(
            string tableName,
            List<string> selectColumns,
            List<FilterParameter> filters,
            string sortColumn,
            string sortDirection,
            int pageNumber,
            int pageSize)
        {
            var parameters = new List<SqlParameter>();

            // Build SELECT clause - column names come from our whitelist, so they're safe
            var columnList = selectColumns != null
                ? string.Join(", ", selectColumns.Select(c => $"[{c}]"))
                : "*";

            // tableName is validated against whitelist, bracket-quoted for safety
            var query = $"SELECT {columnList} FROM [{tableName}]";

            // Build WHERE clause with parameterized values
            if (filters.Any())
            {
                var whereClauses = new List<string>();
                int paramIndex = 0;

                foreach (var filter in filters)
                {
                    // Column names come from our whitelist, so they're safe to use directly
                    // Values are always parameterized
                    if (filter.OperatorKey == "in")
                    {
                        var inValues = filter.Value.Split(',', StringSplitOptions.RemoveEmptyEntries);
                        var inParams = new List<string>();

                        for (int i = 0; i < inValues.Length; i++)
                        {
                            var paramName = $"@p{paramIndex}";
                            paramIndex++;
                            inParams.Add(paramName);
                            parameters.Add(new SqlParameter(paramName, inValues[i].Trim()));
                        }

                        whereClauses.Add($"[{filter.ColumnName}] IN ({string.Join(", ", inParams)})");
                    }
                    else if (filter.OperatorKey == "like")
                    {
                        var paramName = $"@p{paramIndex}";
                        paramIndex++;
                        // Escape special LIKE characters in the user input, then wrap with %
                        var escapedValue = filter.Value
                            .Replace("[", "[[]")
                            .Replace("%", "[%]")
                            .Replace("_", "[_]");
                        parameters.Add(new SqlParameter(paramName, $"%{escapedValue}%"));
                        whereClauses.Add($"[{filter.ColumnName}] LIKE {paramName}");
                    }
                    else
                    {
                        var paramName = $"@p{paramIndex}";
                        paramIndex++;
                        parameters.Add(new SqlParameter(paramName, filter.Value));
                        whereClauses.Add($"[{filter.ColumnName}] {filter.Operator} {paramName}");
                    }
                }

                query += " WHERE " + string.Join(" AND ", whereClauses);
            }

            // Build ORDER BY clause - column name comes from whitelist
            if (!string.IsNullOrEmpty(sortColumn))
            {
                query += $" ORDER BY [{sortColumn}] {sortDirection}";
            }
            else
            {
                // Default ordering required for OFFSET/FETCH
                query += " ORDER BY (SELECT NULL)";
            }

            // Build paging with parameterized values
            var offsetParam = new SqlParameter("@offset", SqlDbType.Int)
            {
                Value = (pageNumber - 1) * pageSize
            };
            var fetchParam = new SqlParameter("@fetch", SqlDbType.Int)
            {
                Value = pageSize
            };
            parameters.Add(offsetParam);
            parameters.Add(fetchParam);

            query += " OFFSET @offset ROWS FETCH NEXT @fetch ROWS ONLY";

            return new QueryResult
            {
                Query = query,
                Parameters = parameters
            };
        }

        private static async Task<List<Dictionary<string, object>>> ExecuteQueryAsync(
            string connectionString,
            string query,
            List<SqlParameter> parameters,
            ILogger log)
        {
            var results = new List<Dictionary<string, object>>();

            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                using (var command = new SqlCommand(query, connection))
                {
                    command.CommandTimeout = 30;
                    command.Parameters.AddRange(parameters.ToArray());

                    log.LogInformation("Executing query: {Query}", query);
                    log.LogInformation("With {ParamCount} parameters", parameters.Count);

                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                var columnName = reader.GetName(i);
                                var value = reader.IsDBNull(i) ? null : reader.GetValue(i);
                                row[columnName] = value;
                            }
                            results.Add(row);
                        }
                    }
                }
            }

            return results;
        }

